import React, { useState, useEffect, useContext } from "react";
import styled from "styled-components";
import ExperienceItem from "./experienceItem.js";
import { InfoContext } from "../../App.js";
import Resume from "./WarrenGabrilloResume.pdf";
// import RitLogo from './ritLogo.png'
import { downloadIcon } from "../../assets/icons.js";

const Experiences = () => {
  const { experiences, isLoading } = useContext(InfoContext);

  const [education, setEducation] = useState();
  const [work, setWork] = useState();

  useEffect(() => {
    if (!isLoading) {
      if (experiences !== undefined) {
        setEducation(
          experiences.filter((experience) => experience.group === "school")
        );
        setWork(
          experiences.filter((experience) => experience.group === "work")
        );
      }
    }
  }, [isLoading, experiences]);

  return (
    <>
      <ExperienceSpan id="experiences" />
      <ExperiencesContainer>
        <ExperiencesContent>
          <ExperiencesHeader>Experiences</ExperiencesHeader>
          <ExperienceSection>
            <ExperienceSectionHeader>Education</ExperienceSectionHeader>
            {education &&
              education.map((school) => {
                return (
                  <ExperienceItem
                    id={school._id}
                    header={school.name}
                    title={school.title}
                    location={school.location}
                    timeline={school.timeline}
                    content={school.content}
                    link={school.link}
                    shortName={school.shortName}
                  />
                );
              })}
          </ExperienceSection>
          <ExperienceSection>
            <ExperienceSectionHeader>Work</ExperienceSectionHeader>
            {work &&
              work.map((position) => {
                return (
                  <ExperienceItem
                    key={position._id}
                    header={position.name}
                    title={position.title}
                    location={position.location}
                    timeline={position.timeline}
                    content={position.content}
                    link={position.link}
                    shortName={position.shortName}
                  />
                );
              })}
          </ExperienceSection>
          <DownloadResume>
            <ResumeIntro>
              Please click below if you'd like a PDF version of my resume!
            </ResumeIntro>
            <ResumeLinkContainer>
              <DownloadIcon>{downloadIcon}</DownloadIcon>
              <ResumeLink href={Resume} download="WarrenGabrilloResume">
                Warren Gabrillo Resume
              </ResumeLink>
            </ResumeLinkContainer>
          </DownloadResume>
        </ExperiencesContent>
      </ExperiencesContainer>
    </>
  );
};

export default Experiences;

const ExperiencesContainer = styled.div`
  background-color: #a0c9d9;
  height: auto;
  display: block;
`;

const ExperienceSpan = styled.span`
  margin-top: -55px;
  padding-bottom: 55px;
  display: block;

  @media only screen and (max-width: 720px) {
    margin-top: 0px;
    padding-bottom: 0px;
  }
`;

const ExperiencesContent = styled.div`
  width: 50%;
  margin: 0px auto;

  div:last-child {
    border-bottom: none;
    padding-bottom: 5px;
  }

  @media only screen and (max-width: 1310px) {
    width: 75%;
  }

  @media only screen and (max-width: 860px) {
    width: 90%;
  }
`;

const ExperiencesHeader = styled.div`
  font-size: 24px;
  color: #1163c6;
  font-weight: bold;
  padding: 25px 0px;
  border-bottom: 1px solid #1163c6;
`;

const ExperienceSection = styled.div`
  padding: 15px 0px 0px;
  border-bottom: 1px solid white;
  display: block;
`;

const ExperienceSectionHeader = styled.div`
  font-size: 24px;
  text-align: left;
  margin-bottom: 15px;
`;

const DownloadResume = styled.div`
  width: 500px;
  height: auto;
  margin: 15px auto 0px;
  display: block;

  a,
  a:link,
  a:visited,
  a:active {
    text-decoration: none;
    color: black;
  }

  a:hover {
    text-decoration: none;
    color: #1163c6;
  }

  @media only screen and (max-width: 720px) {
    font-height: 20px;
    line-height: 35px;
  }

  @media only screen and (max-width: 620px) {
    display: block;
    width: 95%;
  }
`;

const ResumeIntro = styled.div`
  font-family: Poppins;
  font-size: 16px;
`;

const ResumeLink = styled.a``;

const ResumeLinkContainer = styled.div`
  display: flex;
  align-items: center;
  :hover {
    svg {
      fill: #1163c6;
    }

    a {
      text-decoration: none;
      color: #1163c6;
    }
  }
  width: 200px;
  margin: 0px auto;
`;

const DownloadIcon = styled.div`
  svg {
    margin-top: 2px;
  }
`;
