import React, { useState, useEffect, useContext } from "react";
import styled from "styled-components";
import { InfoContext } from "../../App.js";
import SingleSkill from "./singleSkill.js";

const Skills = () => {
  const { skills, isLoading } = useContext(InfoContext);

  const [groups, setGroups] = useState([]);
  const [skillsList, setSkillList] = useState({});

  useEffect(() => {
    if (!isLoading) {
      if (skills !== undefined) {
        const tempGroups = new Set(skills.map((skill) => skill.group));
        const tempMap = skillsList;

        tempGroups.forEach((group) => {
          tempMap[group] = [];
        });

        skills.forEach((skill) => {
          const values = tempMap[skill.group];
          tempMap[skill.group] = [...values, skill];
        });

        setGroups(tempGroups);
        setSkillList(tempMap);
      }
    }
  }, [isLoading, skills]);

  return (
    <SkillsContainer id="skills">
      <SkillsContainerHeader>Skills</SkillsContainerHeader>
      <SkillsColumnContainer>
        {Array.from(groups).map((group, key) => {
          return (
            <SkillsColumn key={key}>
              <SkillsColumnTitle>{group}</SkillsColumnTitle>
              {skillsList[group].map((skill) => {
                return (
                  <SingleSkill
                    key={skill._id}
                    name={skill.name}
                    level={skill.level}
                  />
                );
              })}
            </SkillsColumn>
          );
        })}
      </SkillsColumnContainer>
    </SkillsContainer>
  );
};

export default Skills;

const SkillsContainer = styled.div`
  width: 50%;
  margin: 0px auto 10px;
  display: block;
  font-family: Poppins;

  @media only screen and (max-width: 1310px) {
    width: 75%;
  }

  @media only screen and (max-width: 810px) {
    width: 90%;
  }

  @media only screen and (max-width: 720px) {
    margin-top: 0px;
    padding-bottom: 0px;
  }
`;

const SkillsColumnContainer = styled.div`
  display: flex;

  @media only screen and (max-width: 730px) {
    display: block;
  }
`;

const SkillsContainerHeader = styled.div`
  font-size: 24px;
  color: #1163c6;
  font-weight: bold;
  padding: 15px 0px;
  border-bottom: 1px solid #1163c6;
`;

const SkillsColumn = styled.div`
  display: block;
  flex: 1;
  padding: 0px 10px;
`;

const SkillsColumnTitle = styled.div`
  text-align: center;
  font-weight: bold;
  border-bottom: 1px solid black;
  padding: 10px 0px;
`;
