import React, { useState, useEffect, useRef } from "react";
import styled from "styled-components";
import { xMark, hamburgerIcon } from "../../assets/icons.js";
const Navigation = () => {
  const [showNavMenu, setShowNavMenu] = useState();

  const hamburgerRef = useRef(null);
  const menuRef = useRef(null);

  useEffect(() => {
    window.addEventListener("mousedown", handleClick);
    window.addEventListener("scroll", handleClick);

    return () => {
      window.removeEventListener("mousedown", handleClick);
      window.removeEventListener("scroll", handleClick);
    };
  });

  const handleClick = ({ target }) => {
    if (menuRef && !showNavMenu) {
      return;
    } else if (hamburgerRef && !hamburgerRef.current.contains(target)) {
      setShowNavMenu(false);
    }
  };

  const NavLinks = () => {
    return (
      <NavLinkContainer>
        <NavLink>
          <a href="#about-me">About Me</a>
        </NavLink>
        <NavLink>
          <a href="#experiences">Experiences</a>
        </NavLink>
        <NavLink>
          <a href="#skills">Skills</a>
        </NavLink>
        <NavLink>
          <a href="#contact-me">Contact Me</a>
        </NavLink>
      </NavLinkContainer>
    );
  };

  return (
    <NavigationContainer>
      <NormalNavBar ref={menuRef}>
        <NavLinks />
      </NormalNavBar>
      <HamburgerMenuContainer
        onClick={() => setShowNavMenu(!showNavMenu)}
        ref={hamburgerRef}
      >
        <MenuIcon isShown={showNavMenu}>{hamburgerIcon}</MenuIcon>
        <XIcon isShown={showNavMenu}>{xMark}</XIcon>
        <MenuBar isShown={showNavMenu}>
          <NavLinks isShown={showNavMenu} />
        </MenuBar>
      </HamburgerMenuContainer>
    </NavigationContainer>
  );
};

export default Navigation;

const NavigationContainer = styled.div`
  display: flex;
  position: sticky;
  top: 0px;
  height: 30px;
  width: 100%;
  padding: 15px 0px;
  background-color: white;
  border-bottom: 1px solid lightgray;

  @media only screen and (max-width: 720px) {
    background-color: transparent;
    padding: 0px;
    height 0px;
    border: none;
  }
`;

const NormalNavBar = styled.div`
  width: 100%;
  margin: 0px auto;
  display: flex;

  @media only screen and (max-width: 720px) {
    display: none;
  }

  @media only screen and (max-width: 910px) {
    width: 90%;
  }
`;

const NavLinkContainer = styled.div`
  width: 50%;
  margin: 0px auto;
  display: flex;

  @media only screen and (max-width: 910px) {
    width: 75%;
  }

  @media only screen and (max-width: 720px) {
    display: block;
  }
`;

const NavLink = styled.div`
  height: auto;
  text-transform: uppercase;
  font-size: 18px;
  line-height: 18px;
  padding: 0px 10px;
  item-align: center;
  margin: auto;
  cursor: pointer;

  a,
  a:link,
  a:visited,
  a:active {
    text-decoration: none;
    color: black;
    position: relative;
  }

  a:before {
    content: "";
    position: absolute;
    width: 100%;
    height: 2px;
    bottom: 0px;
    left: -50%;
    background-color: #1163c6;
    opacity: 0;
    transform: scaleX(0);
    transition: all 0.3s ease-in-out 0s;
  }

  a:hover:before {
    opacity: 1;
    left: 0;
    transform: scaleX(1);
  }

  a:hover {
    text-decoration: none;
    color: #1163c6;
  }

  @media only screen and (max-width: 720px) {
    height: 35px;
    font-height: 20px;
    line-height: 35px;
  }
`;

const HamburgerMenuContainer = styled.div`
  display: none;
  width: 100%;

  @media only screen and (max-width: 720px) {
    display: block;
    margin: auto 0px;
    padding: 0px;
    cursor: pointer;
  }
`;

const MenuIcon = styled.div`
  display: ${(props) => (props.isShown ? "none" : "block")};
  background-color: black;
  width: 50px;
  height: 50px;
  border-radius: 5px;
  border: 1px solid lightgray;
  margin: 10px;
  position: absolute;

  svg {
    margin: 5px 5px;
    fill: white;
  }
`;

const XIcon = styled.div`
  display: ${(props) => (props.isShown ? "inline" : "none")};
  width: 50px;
  height: 50px;
  margin: 20px;
  position: absolute;
  left: 0;
  z-index: 1;
`;

const MenuBar = styled.div`
  width: 100%;
  height: auto;
  background-color: white;
  border-bottom: 1px solid lightgray;
  display: ${(props) => (props.isShown ? "block" : "none")};
  position: absolute;
  top: 0;
`;
