import React from "react";
import styled from "styled-components";
import { star } from "../../assets/icons.js";

const SingleSkill = ({ name, level }) => {
  return (
    <SkillContainer>
      <SkillName>{name}</SkillName>
      <Stars>
        <Star isFilled={level >= 1}>{star}</Star>
        <Star isFilled={level >= 2}>{star}</Star>
        <Star isFilled={level >= 3}>{star}</Star>
        <Star isFilled={level >= 4}>{star}</Star>
        <Star isFilled={level === 5}>{star}</Star>
      </Stars>
    </SkillContainer>
  );
};

export default SingleSkill;

const SkillContainer = styled.div`
  display: flex;
  padding: 5px 0px;
`;

const SkillName = styled.div`
  flex: 1;
  text-align: left;
`;

const Stars = styled.div`
  display: flex;
`;

const Star = styled.div`
  svg {
    fill: ${(props) => (props.isFilled ? "#000" : "#bfbfbf")};
  }
`;
