import React, { useState, useEffect, createContext } from "react";
import styled from "styled-components";
import Navigation from "./components/navigation/navigation";
import AboutMe from "./components/aboutMe/aboutMe.js";
import Experiences from "./components/experiences/experiences.js";
import Skills from "./components/skills/skills.js";
import ContactMe from "./components/contactMe/contactMe.js";
import skyline from "./assets/images/skyline.jpg";

export const InfoContext = createContext({});

function App() {
  const [isLoading, setIsLoading] = useState(false);
  const [experiences, setExperiences] = useState();
  const [skills, setSkills] = useState();

  const getAPI = async () => {
    setIsLoading(true);
    const response = await fetch("/api/data");
    const data = await response.json();

    try {
      setExperiences(data["experiences"]);
      setSkills(data["skills"]);
      setIsLoading(false);
    } catch (error) {
      console.log("error", error);
    }
  };

  useEffect(() => {
    getAPI();
  }, []);

  return (
    <InfoContext.Provider value={{ experiences, skills, isLoading }}>
      <Navigation />
      <Container>
        <HeaderImage>
          <HeaderTitle>Warren R. Gabrillo</HeaderTitle>
        </HeaderImage>
      </Container>
      <AboutMe />
      <Experiences />
      <Skills />
      <ContactMe />
      <Footer>Created by Warren R. Gabrillo &#169; 2021</Footer>
    </InfoContext.Provider>
  );
}

export default App;

const Container = styled.div``;

const HeaderImage = styled.div`
  height: 93vh;
  background-image: url(${skyline});
  background-position: center;
  background-size: cover;
  display: flex;
  justify-content: center;
  align-items: center;
`;

const HeaderTitle = styled.div`
  width: 500px;
  font-size: 50px;
  color: white;
  text-transform: uppercase;
`;

const Footer = styled.div`
  height: 30px;
  width: 100%;
  text-align: center;
  font-size: 16px;
  font-weight: 300px;
  line-height: 30px;
`;
